package com.example.auth.security;

import com.example.auth.entity.AppUser;
import com.example.auth.service.BackupCodeService;
import com.example.auth.service.CustomUserDetailsService;
import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.authentication.BadCredentialsException;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.AuthenticationException;
import org.springframework.stereotype.Component;

@Component
@RequiredArgsConstructor
public class BackupCodeAuthenticationProvider implements AuthenticationProvider {

    private final BackupCodeService backupCodeService;
    private final CustomUserDetailsService userDetailsService;

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        String username = authentication.getName();
        String backupCode = String.valueOf(authentication.getCredentials());

        AppUser user = userDetailsService.loadDomainUserByUsername(username);
        if (!user.isMfaEnabled()) {
            throw new BadCredentialsException("MFA is not enabled for this user");
        }

        boolean valid = backupCodeService.consumeBackupCode(user, backupCode);
        if (!valid) {
            throw new BadCredentialsException("Invalid backup code");
        }

        var userDetails = userDetailsService.loadUserByUsername(username);
        return new BackupCodeAuthenticationToken(userDetails, null, userDetails.getAuthorities());
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return BackupCodeAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

package com.example.auth.service;

import io.jsonwebtoken.Claims;
import io.jsonwebtoken.Jwts;
import io.jsonwebtoken.io.Decoders;
import io.jsonwebtoken.security.Keys;
import org.springframework.security.core.userdetails.UserDetails;
import org.springframework.stereotype.Service;

import javax.crypto.SecretKey;
import java.util.Date;

@Service
public class JwtService {

    private static final String SECRET = "VGhpc0lzQVNlY3VyZUFuZExvbmdFbm91Z2hTZWNyZXRLZXlGb3JKV1RUZXN0aW5nMTIzNDU2";
    private static final long EXPIRATION = 1000L * 60 * 60 * 8;

    public String generateToken(UserDetails userDetails) {
        return Jwts.builder()
            .subject(userDetails.getUsername())
            .issuedAt(new Date())
            .expiration(new Date(System.currentTimeMillis() + EXPIRATION))
            .signWith(getSignInKey())
            .compact();
    }

    public Claims extractAllClaims(String token) {
        return Jwts.parser().verifyWith(getSignInKey()).build().parseSignedClaims(token).getPayload();
    }

    public boolean isTokenValid(String token, UserDetails userDetails) {
        String username = extractAllClaims(token).getSubject();
        Date expiration = extractAllClaims(token).getExpiration();
        return username.equals(userDetails.getUsername()) && expiration.after(new Date());
    }

    private SecretKey getSignInKey() {
        byte[] keyBytes = Decoders.BASE64.decode(SECRET);
        return Keys.hmacShaKeyFor(keyBytes);
    }
}

