package com.example.auth.service;

import com.example.auth.entity.AppUser;
import com.example.auth.entity.BackupCode;
import com.example.auth.repository.BackupCodeRepository;
import jakarta.transaction.Transactional;
import lombok.RequiredArgsConstructor;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

import java.security.SecureRandom;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

@Service
@RequiredArgsConstructor
public class BackupCodeService {

    private static final String CHARS = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
    private static final int CODE_LENGTH = 10;
    private static final int DEFAULT_CODE_COUNT = 10;

    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    @Transactional
    public List<String> generateAndStoreBackupCodes(AppUser user) {
        backupCodeRepository.deleteByUserId(user.getId());

        List<String> rawCodes = new ArrayList<>();
        List<BackupCode> entities = new ArrayList<>();

        for (int i = 0; i < DEFAULT_CODE_COUNT; i++) {
            String rawCode = generateCode();
            rawCodes.add(rawCode);
            entities.add(
                BackupCode.builder()
                    .codeHash(passwordEncoder.encode(rawCode))
                    .used(false)
                    .user(user)
                    .build()
            );
        }

        backupCodeRepository.saveAll(entities);
        return rawCodes;
    }

    @Transactional
    public boolean consumeBackupCode(AppUser user, String rawCode) {
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        for (BackupCode code : codes) {
            if (passwordEncoder.matches(normalize(rawCode), code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(LocalDateTime.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    private String generateCode() {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < CODE_LENGTH; i++) {
            sb.append(CHARS.charAt(secureRandom.nextInt(CHARS.length())));
        }
        return format(sb.toString());
    }

    private String format(String code) {
        return code.substring(0, 5) + "-" + code.substring(5);
    }

    private String normalize(String code) {
        return code == null ? null : code.replace("-", "").trim().toUpperCase();
    }
}

package com.example.auth.service;

import com.example.auth.dto.*;
import com.example.auth.entity.AppUser;
import com.example.auth.repository.AppUserRepository;
import com.example.auth.security.BackupCodeAuthenticationToken;
import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class AuthService {

    private final AppUserRepository appUserRepository;
    private final PasswordEncoder passwordEncoder;
    private final AuthenticationManager authenticationManager;
    private final JwtService jwtService;
    private final BackupCodeService backupCodeService;

    public AuthResponse register(RegisterRequest request) {
        if (appUserRepository.existsByUsername(request.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (appUserRepository.existsByEmail(request.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }

        AppUser user = AppUser.builder()
            .username(request.getUsername())
            .email(request.getEmail())
            .password(passwordEncoder.encode(request.getPassword()))
            .mfaEnabled(false)
            .build();

        appUserRepository.save(user);
        return AuthResponse.builder()
            .message("User registered successfully")
            .build();
    }

    public AuthResponse login(LoginRequest request) {
        var authentication = authenticationManager.authenticate(
            new UsernamePasswordAuthenticationToken(request.getUsername(), request.getPassword())
        );

        String token = jwtService.generateToken((org.springframework.security.core.userdetails.UserDetails) authentication.getPrincipal());
        return AuthResponse.builder()
            .token(token)
            .message("Authenticated successfully")
            .build();
    }

    public AuthResponse backupCodeLogin(BackupCodeLoginRequest request) {
        var authentication = authenticationManager.authenticate(
            new BackupCodeAuthenticationToken(request.getUsername(), request.getBackupCode())
        );

        String token = jwtService.generateToken((org.springframework.security.core.userdetails.UserDetails) authentication.getPrincipal());
        return AuthResponse.builder()
            .token(token)
            .message("Authenticated using backup code")
            .build();
    }

    public MfaEnableResponse enableMfa(String username) {
        AppUser user = appUserRepository.findByUsername(username)
            .orElseThrow(() -> new IllegalArgumentException("User not found"));

        user.setMfaEnabled(true);
        user.setMfaSecret("ENTERPRISE-MFA-SECRET-" + user.getId());
        appUserRepository.save(user);

        var backupCodes = backupCodeService.generateAndStoreBackupCodes(user);
        return MfaEnableResponse.builder()
            .message("MFA enabled and backup codes generated")
            .backupCodes(backupCodes)
            .build();
    }

    public BackupCodesResponse regenerateBackupCodes(String username) {
        AppUser user = appUserRepository.findByUsername(username)
            .orElseThrow(() -> new IllegalArgumentException("User not found"));

        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA must be enabled before generating backup codes");
        }

        var backupCodes = backupCodeService.generateAndStoreBackupCodes(user);
        return BackupCodesResponse.builder()
            .message("Backup codes regenerated successfully")
            .backupCodes(backupCodes)
            .build();
    }
}

package com.example.auth.controller;

import com.example.auth.dto.*;
import com.example.auth.service.AuthService;
import lombok.RequiredArgsConstructor;
import org.springframework.security.core.Authentication;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
@RequiredArgsConstructor
public class AuthController {

    private final AuthService authService;

    @PostMapping("/register")
    public AuthResponse register(@RequestBody RegisterRequest request) {
        return authService.register(request);
    }

    @PostMapping("/login")
    public AuthResponse login(@RequestBody LoginRequest request) {
        return authService.login(request);
    }

    @PostMapping("/mfa/enable")
    public MfaEnableResponse enableMfa(Authentication authentication) {
        return authService.enableMfa(authentication.getName());
    }

    @PostMapping("/mfa/regenerate-backup-codes")
    public BackupCodesResponse regenerateBackupCodes(Authentication authentication) {
        return authService.regenerateBackupCodes(authentication.getName());
    }

    @PostMapping("/mfa/backup-login")
    public AuthResponse backupCodeLogin(@RequestBody BackupCodeLoginRequest request) {
        return authService.backupCodeLogin(request);
    }
}

