import java.util.Map;

@RestController
@RequestMapping("/api/account")
@RequiredArgsConstructor
public class AccountController {

    private final AppUserRepository appUserRepository;
    private final RecoveryService recoveryService;

    @GetMapping("/backup-codes/remaining")
    public Map<String, Object> remaining(Authentication authentication) {
        var user = appUserRepository.findByUsername(authentication.getName()).orElseThrow();
        return Map.of(
            "username", user.getUsername(),
            "remainingBackupCodes", recoveryService.getRemainingBackupCodes(user)
        );
    }
}

